\set ON_ERROR_STOP on
set client_min_messages=warning;
create schema if not exists task18_test;
create or replace function task18_test.assert(p boolean, label text) returns void language plpgsql as $$ begin if not coalesce(p,false) then raise exception 'TASK18_ASSERTION_FAILED: %', label; end if; end $$;
create or replace function task18_test.expect_error(label text, expected text, sql text) returns void language plpgsql as $$ begin execute sql; raise exception 'TASK18_EXPECTED_ERROR_NOT_RAISED: %', label; exception when others then if position(expected in sqlerrm)=0 then raise exception 'TASK18_WRONG_ERROR % expected % got %', label, expected, sqlerrm; end if; end $$;

select task18_test.assert(to_regclass('public.creator_publishing_operator_completion_evidence_intents') is not null,'evidence table exists');
select task18_test.assert((select relrowsecurity from pg_class where oid='public.creator_publishing_operator_completion_evidence_intents'::regclass),'evidence RLS enabled');
select task18_test.assert(not has_function_privilege('authenticated','public.creator_publishing_complete_onlyfans_manual_post(text,uuid,uuid,text,uuid,text,text,text,int,text,uuid)','execute'),'completion rpc not authenticated');
select task18_test.assert((select count(*)=1 from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and contype='c' and pg_get_constraintdef(oid) like '%action_type%'),'exactly one action_type check remains');
select task18_test.assert((select conname='task18_operator_action_type_check' from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and contype='c' and pg_get_constraintdef(oid) like '%action_type%'),'stable task18 action_type constraint name');
select task18_test.assert((select pg_get_constraintdef(oid) from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and conname='task18_operator_action_type_check') like '%claim%' and (select pg_get_constraintdef(oid) from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and conname='task18_operator_action_type_check') like '%release%' and (select pg_get_constraintdef(oid) from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and conname='task18_operator_action_type_check') like '%progress_update%' and (select pg_get_constraintdef(oid) from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and conname='task18_operator_action_type_check') like '%expired_claim_recovery%' and (select pg_get_constraintdef(oid) from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and conname='task18_operator_action_type_check') like '%manual_completion%','action_type definition permits all five actions');
select task18_test.assert(not exists(select 1 from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and conname='creator_publishing_operator_action_idempotenc_action_type_check'),'old generated Task 17A action_type constraint removed');
select task18_test.assert(not exists(select 1 from pg_constraint where conrelid='public.creator_publishing_operator_action_idempotency'::regclass and conname='creator_publishing_operator_action_idempotency_action_type_check'),'accidental long Task 18 action_type constraint removed');

